import { useState } from "react";

const AddFixture = ({currentFixtures, setFixtureIntoArray} : any) => {

    const [fixture, setFixture] = useState({homeTeam: "", awayTeam: "", homeScore: "0", awayScore: "0", result: ""});

    const submit = (e : any) =>
    {
        e.preventDefault();        
        setFixtureIntoArray([...currentFixtures,
            {
                id: currentFixtures.length + 1,
                date: Date().toString(),
                result: fixture.result,
                homeTeam: fixture.homeTeam,
                awayTeam: fixture.awayTeam,
                homeScore: fixture.homeScore,
                awayScore: fixture.awayScore,
                fixture: "League"
            }
        ]);
    }

    return (
        <>
        <label for="hometeam">Home Team</label>
        <input title="hometeam" type="text" name="hometeam" value={fixture.homeTeam} onChange={(e) => setFixture({...fixture, homeTeam : e.target.value})}></input>        
        <input title="homeScore" type="text" name="homeScore" value={fixture.homeScore} onChange={(e) => setFixture({...fixture, homeScore : e.target.value})}></input>        
        <input title="awayTeam" type="text" name="awayTeam" value={fixture.awayTeam} onChange={(e) => setFixture({...fixture, awayTeam : e.target.value})}></input>        
        <input title="awayScore" type="text" name="awayScore" value={fixture.awayScore} onChange={(e) => setFixture({...fixture, awayScore : e.target.value})}></input>        
        <input title="result" type="text" name="result" value={fixture.result} onChange={(e) => setFixture({...fixture, result : e.target.value})}></input>        
        <button onClick={submit}>Add</button>
        </>
    );
}

export default AddFixture;
